std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file_buffer object using the provided file path
    hexi::file_buffer file_buf(file_path);

    // Check if the file buffer was successfully opened (using the boolean conversion operator)
    if (!file_buf) {
        return {}; // Return empty vector if file opening failed
    }

    // Create a vector to store the header data with the specified size
    std::vector<uint8_t> header_data(header_size);

    // Use the peek method to copy the header data from the file buffer to the vector
    // without advancing the read pointer
    file_buf.peek(header_data.data(), header_size);

    // Return the vector containing the header data
    return header_data;
}
```

