```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Use the varint_encode function from hexi::detail namespace
    // The writer.buffer_ provides the buffer_write interface required by varint_encode
    return varint_encode(writer.buffer_, static_cast<std::size_t>(value));
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use the varint_decode function from hexi::detail namespace
    // The reader.buffer_ provides the buffer_read interface required by varint_decode
    return static_cast<T>(varint_decode(reader.buffer_));
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;

    // Create buffer adaptor for the vector
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create writer and reader using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the value
    std::size_t bytes_written = encode_varint(writer, original_value);

    // Reset reader position to beginning (seek to start)
    // Since we're using a fresh reader, it should start at position 0
    // If needed, we could use: reader.buffer_.read_seek(hexi::buffer_seek::sk_buffer_absolute, 0);

    // Decode the value
    T decoded_value = decode_varint(reader);

    // Verify the roundtrip
    bool success = (decoded_value == original_value);

    // Additional verification: check that we wrote at least one byte
    bool valid_encoding = (bytes_written > 0);

    return success && valid_encoding;
}
```

