Based on the reference materials and detailed specifications, here's the complete implementation of the required functions:

```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor and write data
    hexi::pmc::buffer_write_adaptor adaptor_write(buffer);

    // Check available space and resize if needed
    if (adaptor_write.free() < input_data.size()) {
        buffer.resize(input_data.size());
    }

    // Write the input data to the buffer
    adaptor_write.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor and read data back
    hexi::pmc::buffer_read_adaptor adaptor_read(buffer);

    // Check readable size
    std::size_t readable_size = adaptor_read.size();

    // Read the data back into a new vector
    std::vector<uint8_t> output(readable_size);
    adaptor_read.read(output.data(), readable_size);

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor adaptor(buffer_data);

    // Get pointer to current read position
    const uint8_t* read_ptr = adaptor.read_ptr();

    // Copy data without advancing the read pointer
    std::vector<uint8_t> peeked_data(peek_size);
    adaptor.copy(peeked_data.data(), peek_size);

    // Consume the data by reading (advances the read pointer)
    adaptor.read(peeked_data.data(), peek_size);

    return peeked_data;
}
```

